package com.example.demo.services;import com.example.demo.dto.AuditoriaDTO;import com.example.demo.models.*;import com.example.demo.repository.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.*;import java.time.LocalDateTime;import java.util.List;
@Service public class AuditoriaService{private final AuditoriaRepository repository;private final PersonaRepository personas;public AuditoriaService(AuditoriaRepository repository,PersonaRepository personas){this.repository=repository;this.personas=personas;}@Transactional(propagation=Propagation.REQUIRES_NEW)public void registrar(Long usuarioId,String accion,String entidad,Object entidadId,String detalle){repository.save(Auditoria.builder().fecha(LocalDateTime.now()).usuario(usuarioId==null?null:personas.findById(usuarioId).orElse(null)).accion(accion).entidad(entidad).entidadId(entidadId==null?null:String.valueOf(entidadId)).detalle(detalle).build());}@Transactional(readOnly=true)public List<AuditoriaDTO> listar(){return repository.findAllByOrderByFechaDesc().stream().map(this::dto).toList();}@Transactional(readOnly=true)public org.springframework.data.domain.Page<AuditoriaDTO> listar(org.springframework.data.domain.Pageable pageable){return repository.findAll(pageable).map(this::dto);}@Transactional(readOnly=true)public long cantidad(){return repository.count();}private AuditoriaDTO dto(Auditoria a){return new AuditoriaDTO(a.getId(),a.getFecha(),a.getUsuario()==null?"Sistema":a.getUsuario().getNombre()+" "+a.getUsuario().getApellido(),a.getAccion(),a.getEntidad(),a.getEntidadId(),a.getDetalle());}}
